targets.expr:
sum(
  sum_over_time(
    (
      (100 - (avg by (instance) (irate(node_cpu_seconds_total{server="$server", mode="idle"}[1m])) * 100)) 
      > bool (
        ((${threshold} == bool 1) * 50) +
        ((${threshold} == bool 2) * 60) +
        ((${threshold} == bool 3) * 75) +
        ((${threshold} == bool 4) * 90)
      )
    )[$__range:15s]
  )
) or on() vector(0)
